async function checkEventStreamApi() {
  let closed = false;
  const server = createDevServer({
    cwd: ROOT,
    eventStreamFn: async ({ onEvent }) => {
      onEvent({
        method: "item/agentMessage/delta",
        threadIdSuffix: "abcd1234",
        turnIdSuffix: "turn1234",
        itemType: "agentMessage",
        status: "inProgress",
        liveText: {
          role: "agent",
          text: "Live answer references /tmp/codex-app-port-verify/secret.txt and token=sk-proj-verifysecret",
        },
        text: "Sensitive streamed content",
        cwd: ROOT,
      });
      onEvent({
        method: "item/agentMessage/delta",
        threadIdSuffix: "wxyz9876",
        turnIdSuffix: "turn9999",
        itemType: "agentMessage",
        status: "inProgress",
        liveText: {
          role: "agent",
          text: "Excluded live answer",
        },
      });
      return {
        initialize: {
          platformOs: "linux",
          platformFamily: "unix",
          userAgent: "verify-sensitive-agent",
          codexHome: "/tmp/verify-private-home",
        },
        close() {
          closed = true;
        },
      };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const withoutToken = await fetch(`${baseUrl}/api/event-stream?durationMs=1`);
    if (withoutToken.status !== 403) {
      throw new Error(`event stream API without token returned HTTP ${withoutToken.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const invalid = await fetch(`${baseUrl}/api/event-stream?durationMs=10&thread=../secret`, {
      headers: apiHeaders(token),
    });
    if (invalid.status !== 400) {
      throw new Error(`invalid event stream thread filter returned HTTP ${invalid.status}`);
    }

    const response = await fetch(`${baseUrl}/api/event-stream?durationMs=10&thread=abcd1234`, {
      headers: apiHeaders(token),
    });
    if (!response.ok) {
      throw new Error(`event stream API returned HTTP ${response.status}`);
    }
    const body = await response.text();
    assertSanitizedEventStream(body);
    if (!closed) {
      throw new Error("event stream did not close the app-server connection");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server event stream returns sanitized notifications and live text");
}

async function checkTurnPreflightApi() {
  let probeCalled = false;
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const withoutToken = await fetch(`${baseUrl}/api/turn-preflight`, {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
      },
      body: JSON.stringify({
        thread: "abcd1234",
        prompt: "Sensitive prompt without token",
      }),
    });
    if (withoutToken.status !== 403) {
      throw new Error(`turn preflight API without token returned HTTP ${withoutToken.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const response = await fetch(`${baseUrl}/api/turn-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "default",
        thread: "abcd1234",
        prompt: "Sensitive user prompt that must not be echoed",
      }),
    });
    if (!response.ok) {
      throw new Error(`turn preflight API returned HTTP ${response.status}`);
    }
    assertSanitizedTurnPreflight(await response.json());

    const invalid = await fetch(`${baseUrl}/api/turn-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        thread: "../abcd",
        prompt: "Sensitive invalid prompt",
      }),
    });
    if (invalid.status !== 400) {
      throw new Error(`invalid turn preflight returned HTTP ${invalid.status}`);
    }
    if ((await invalid.text()).includes("Sensitive invalid prompt")) {
      throw new Error("invalid turn preflight response leaked prompt content");
    }

    if (probeCalled) {
      throw new Error("turn preflight called the app-server probe");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server turn preflight validates without model traffic");
}

async function checkThreadStartApi() {
  const actionAuditDir = await mkdtemp(join(tmpdir(), "codex-verify-thread-start-audit-"));
  const actionAuditLogPath = join(actionAuditDir, "actions.jsonl");
  const calls = [];
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    threadStartEnabled: true,
    threadStartFn: async (options) => {
      calls.push(options);
      return {
        ok: true,
        generatedAt: "2026-05-16T00:00:00.000Z",
        transport: "stdio-jsonl",
        protocol: "json-rpc-2.0-without-jsonrpc-field",
        initialize: {
          platformFamily: "unix",
          platformOs: "linux",
          codexHome: "/tmp/verify-private-home",
          userAgent: "verify-private-agent",
        },
        probes: {
          threadStart: {
            method: "thread/start",
            threadIdSuffix: "abcd1234",
            status: "idle",
            source: "appServer",
            modelProvider: "openai",
            cwdBasename: "codex-app-port-verify",
            ephemeral: false,
            approvalPolicy: "on-request",
            approvalsReviewer: "user",
            sandbox: "read-only",
            environmentCount: 0,
            promptTextReturned: true,
            threadContentReturned: true,
            fullIdsReturned: true,
            cwdReturned: true,
            pathsReturned: true,
            instructionSourcesReturned: true,
          },
        },
        notifications: {},
      };
    },
    actionAuditLog: createActionAuditLog({
      path: actionAuditLogPath,
      now: () => "2026-05-16T00:00:00.000Z",
    }),
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const token = await readUiSessionToken(baseUrl);
    const preflightResponse = await fetch(`${baseUrl}/api/thread-start-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({}),
    });
    if (!preflightResponse.ok) {
      throw new Error(`thread start preflight returned HTTP ${preflightResponse.status}`);
    }
    const preflightPayload = await preflightResponse.json();
    if (
      preflightPayload.action?.type !== "thread-start-preflight" ||
      preflightPayload.policy?.executionGateEnabled !== true ||
      preflightPayload.thread?.cwdReturned !== false
    ) {
      throw new Error("thread start preflight did not preserve the gated shape");
    }
    assertActionPreflight(preflightPayload, "thread-start-preflight", "default");

    const response = await fetch(`${baseUrl}/api/thread-start`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (!response.ok) {
      throw new Error(`thread start returned HTTP ${response.status}`);
    }
    const payload = await response.json();
    assertSanitizedThreadStart(payload, {
      token: preflightPayload.preflight.token,
    });
    if (calls.length !== 1 || calls[0].cwd !== "/tmp/codex-app-port-verify") {
      throw new Error("thread start did not call the app-server thread/start probe once");
    }

    const replayResponse = await fetch(`${baseUrl}/api/thread-start`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        preflightToken: preflightPayload.preflight.token,
      }),
    });
    if (replayResponse.status !== 409) {
      throw new Error(`thread start replay returned HTTP ${replayResponse.status}`);
    }

    const auditRecords = (await readFile(actionAuditLogPath, "utf8"))
      .trim()
      .split("\n")
      .map((line) => JSON.parse(line));
    if (
      auditRecords.length !== 1 ||
      auditRecords[0].event !== "thread-start-recorded" ||
      auditRecords[0].action?.type !== "thread-start" ||
      auditRecords[0].target?.threadIdSuffix !== "abcd1234"
    ) {
      throw new Error("thread start audit record did not preserve sanitized metadata");
    }
    assertNoMarkers(JSON.stringify(auditRecords), [
      preflightPayload.preflight.token,
      "/tmp/codex-app-port-verify",
      "/tmp/verify-private-home",
      "verify-private-agent",
      "\"promptTextReturned\":true",
      "\"fullIdsReturned\":true",
    ]);

    const gateResponse = await fetch(`${baseUrl}/api/execution-gate`, {
      headers: jsonHeaders(token),
    });
    if (!gateResponse.ok) {
      throw new Error(`thread start execution gate history returned HTTP ${gateResponse.status}`);
    }
    assertSanitizedThreadLifecycleActionHistory(await gateResponse.json(), {
      count: 1,
      type: "thread-start",
      method: "thread/start",
      threadIdSuffix: "abcd1234",
      consumedPreflightToken: preflightPayload.preflight.token,
      appServerTraffic: true,
      modelTraffic: false,
      threadCreated: true,
    });
  } finally {
    await closeServer(server);
    await rm(actionAuditDir, { recursive: true, force: true });
  }
  pass("dev server thread start consumes opt-in one-time tokens without model traffic");
}

