async function checkSettingsIntegrationsApi() {
  let probeCalled = false;
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    workspaceInputs: ["/tmp/codex-app-port-verify-extra"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const withoutToken = await fetch(`${baseUrl}/api/settings-integrations`);
    if (withoutToken.status !== 403) {
      throw new Error(`settings integrations API without token returned HTTP ${withoutToken.status}`);
    }

    const token = await readUiSessionToken(baseUrl);
    const wrongMethod = await fetch(`${baseUrl}/api/settings-integrations`, {
      method: "POST",
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`settings integrations POST returned HTTP ${wrongMethod.status}`);
    }

    const response = await fetch(`${baseUrl}/api/settings-integrations?workspace=workspace-2`, {
      headers: apiHeaders(token),
    });
    if (!response.ok) {
      throw new Error(`settings integrations API returned HTTP ${response.status}`);
    }
    assertSanitizedSettingsIntegrations(await response.json());

    const invalid = await fetch(
      `${baseUrl}/api/settings-integrations?workspace=/tmp/codex-app-port-verify`,
      {
        headers: apiHeaders(token),
      },
    );
    if (invalid.status !== 404) {
      throw new Error(`invalid settings integrations workspace returned HTTP ${invalid.status}`);
    }

    if (probeCalled) {
      throw new Error("settings integrations API called the app-server probe");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server settings integrations boundary is blocked without app-server traffic");
}

