async function checkMcpResourcePreflightApi() {
  let probeCalled = false;
  const server = createDevServer({
    cwd: "/tmp/codex-app-port-verify",
    workspaceInputs: ["/tmp/codex-app-port-verify-extra"],
    probeFn: async () => {
      probeCalled = true;
      return { ok: true };
    },
  });
  const port = await listenWithFallback(server, { host: "127.0.0.1", port: 0 });
  const baseUrl = `http://127.0.0.1:${port}`;

  try {
    const token = await readUiSessionToken(baseUrl);
    const wrongMethod = await fetch(`${baseUrl}/api/mcp-resource-preflight`, {
      headers: apiHeaders(token),
    });
    if (wrongMethod.status !== 405) {
      throw new Error(`MCP resource preflight GET returned HTTP ${wrongMethod.status}`);
    }

    const resource = "file:///tmp/codex-app-port-verify-extra/secret.txt?token=sk-proj-verifysecret";
    const response = await fetch(`${baseUrl}/api/mcp-resource-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        server: "verify-private-mcp",
        resource,
      }),
    });
    if (!response.ok) {
      throw new Error(`MCP resource preflight returned HTTP ${response.status}`);
    }
    const payload = await response.json();
    assertSanitizedMcpResourcePreflight(payload, {
      resourceLength: resource.length,
    });

    const historyResponse = await fetch(`${baseUrl}/api/settings-integrations?workspace=workspace-2`, {
      headers: apiHeaders(token),
    });
    if (!historyResponse.ok) {
      throw new Error(`MCP resource preflight history returned HTTP ${historyResponse.status}`);
    }
    assertSanitizedIntegrationPreflightHistory(await historyResponse.json(), {
      type: "mcp-resource-preflight",
      method: "mcpServer/resource/read",
      token: payload.preflight.token,
      serverLength: "verify-private-mcp".length,
      resourceLength: resource.length,
      argsLength: 0,
      argKeys: 0,
    });

    const invalid = await fetch(`${baseUrl}/api/mcp-resource-preflight`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        server: "verify-private-mcp",
        resource: "   ",
      }),
    });
    if (invalid.status !== 400) {
      throw new Error(`invalid MCP resource preflight returned HTTP ${invalid.status}`);
    }
    if ((await invalid.text()).includes("verify-private-mcp")) {
      throw new Error("invalid MCP resource preflight leaked the server name");
    }

    if (probeCalled) {
      throw new Error("MCP resource preflight called the app-server probe");
    }
  } finally {
    await closeServer(server);
  }
  pass("dev server MCP resource preflight blocks resource reads");
}

