    const blocked = await fetch(`${disabledBaseUrl}/api/environment-add`, {
      method: "POST",
      headers: jsonHeaders(token),
      body: JSON.stringify({
        workspace: "workspace-2",
        environmentId,
        execServerUrl,
        preflightToken: preflightPayload.preflight.token,
      }),
    });
