function assertSafeInstallResult(result, { expectWritten, home, expectUrlHandler = false }) {
  if (!result.ok || result.written !== expectWritten) {
    throw new Error("local installer returned an unexpected status");
  }
  assertPathInsideDirectory(result.installDir, home, "local installer install directory");
  assertPathInsideDirectory(result.desktopDir, home, "local installer desktop directory");
  if (result.desktopPath) {
    assertPathInsideDirectory(result.desktopPath, home, "local installer desktop path");
  }
  if (!Array.isArray(result.copyEntries) || !result.copyEntries.includes("scripts")) {
    throw new Error("local installer did not plan runtime files");
  }
  if (!result.copyEntries.includes("assets")) {
    throw new Error("local installer did not plan icon assets");
  }
  assertGuardrailsFalse("local installer", result.guardrails, [
    "network",
    "sudo",
    "globalPackages",
    "officialCodexUrlHandler",
    "startsServerFromUrl",
    "electronSandboxDisabled",
    "symlinksAllowed",
  ]);
  if (Boolean(result.guardrails?.urlHandler) !== expectUrlHandler) {
    throw new Error("local installer URL handler guardrail did not match expectation");
  }
  assertSafeDesktopEntry(result.desktopEntry, home);
  if (expectUrlHandler) {
    assertPathInsideDirectory(
      result.urlHandlerDesktopPath,
      home,
      "local installer URL handler desktop path",
    );
    assertSafeUrlHandlerDesktopEntry(result.urlHandlerDesktopEntry, home);
  } else if (result.urlHandlerDesktopPath || result.urlHandlerDesktopEntry) {
    throw new Error("local installer unexpectedly returned a URL handler entry");
  }
}

function assertSafePackageResult(result, { expectWritten, outDir }) {
  if (!result.ok || result.written !== expectWritten) {
    throw new Error("local packager returned an unexpected status");
  }
  assertPathInsideDirectory(result.archivePath, outDir, "local packager archive path");
  assertPathInsideDirectory(result.sha256Path, outDir, "local packager checksum path");
  if (result.name !== "codex-app-port" || result.version !== "0.1.0") {
    throw new Error("local packager returned unexpected package identity");
  }
  if (
    result.archiveRoot !== `${result.name}-${result.version}` ||
    result.archiveFilename !== `${result.archiveRoot}.tar.gz`
  ) {
    throw new Error("local packager returned inconsistent archive metadata");
  }
  if (!Array.isArray(result.packageEntries) || !result.packageEntries.includes("src")) {
    throw new Error("local packager did not include runtime source entries");
  }
  for (const entry of ["assets", "docs", "package.json", "packaging", "scripts", "ui"]) {
    if (!result.packageEntries.includes(entry)) {
      throw new Error(`local packager did not include ${entry}`);
    }
  }
  if (expectWritten && !/^[a-f0-9]{64}$/.test(result.sha256 ?? "")) {
    throw new Error("local packager did not return a SHA-256 digest");
  }
  if (!expectWritten && result.sha256 !== null) {
    throw new Error("local packager dry run returned a digest");
  }
  assertGuardrailsFalse("local packager", result.guardrails, [
    "network",
    "sudo",
    "globalPackages",
    "autoUpdate",
    "urlHandler",
    "symlinksAllowed",
  ]);
}

function assertSafeArchPackageResult(result, { outDir }) {
  if (!result.ok || result.written !== true || result.sourceLocal !== true) {
    throw new Error("Arch packager returned an unexpected status");
  }
  assertPathInsideDirectory(result.pkgbuildPath, outDir, "Arch packager PKGBUILD path");
  assertPathInsideDirectory(result.archivePath, outDir, "Arch packager archive path");
  assertPathInsideDirectory(result.sha256Path, outDir, "Arch packager checksum path");
  if (result.name !== "codex-app-port" || result.version !== "0.1.0") {
    throw new Error("Arch packager returned unexpected package identity");
  }
  if (result.archiveFilename !== `${result.name}-${result.version}.tar.gz`) {
    throw new Error("Arch packager returned inconsistent archive metadata");
  }
  if (!/^[a-f0-9]{64}$/.test(result.sha256 ?? "")) {
    throw new Error("Arch packager did not return a SHA-256 digest");
  }
  assertGuardrailsFalse("Arch packager", result.guardrails, [
    "network",
    "sudo",
    "postInstall",
    "systemd",
    "packageManagerInstall",
    "autoUpdate",
    "urlHandler",
    "scriptInstallsPackage",
  ]);
}

function assertGuardrailsFalse(label, guardrails, names) {
  for (const name of names) {
    if (guardrails?.[name] !== false) {
      throw new Error(`${label} guardrail ${name} is not disabled/false`);
    }
  }
}

function assertPathInsideDirectory(path, directory, label) {
  if (typeof path !== "string" || typeof directory !== "string") {
    throw new Error(`${label} is missing`);
  }
  const rel = pathRelative(directory, path);
  if (!rel || rel === ".." || rel.startsWith(`..${sep}`) || isAbsolute(rel)) {
    throw new Error(`${label} escaped the selected directory`);
  }
}

function assertSafeDesktopEntry(content, home) {
  if (typeof content !== "string" || !content.includes("Type=Application")) {
    throw new Error("local desktop entry is missing Type=Application");
  }
  if (!content.includes(home) || !content.includes("scripts/desktop-launcher.mjs")) {
    throw new Error("local desktop entry does not target the installed launcher");
  }
  if (!content.includes("assets/app-icon.svg")) {
    throw new Error("local desktop entry does not target the installed icon");
  }
  for (const forbidden of ["MimeType=", "x-scheme-handler", `--no-${"sandbox"}`]) {
    if (content.includes(forbidden)) {
      throw new Error(`local desktop entry contains forbidden marker ${forbidden}`);
    }
  }
}

function assertSafeUrlHandlerDesktopEntry(content, home) {
  if (typeof content !== "string" || !content.includes("Type=Application")) {
    throw new Error("URL handler desktop entry is missing Type=Application");
  }
  if (!content.includes(home) || !content.includes("scripts/url-handler.mjs")) {
    throw new Error("URL handler desktop entry does not target the installed handler");
  }
  if (!content.includes("--open %u")) {
    throw new Error("URL handler desktop entry does not pass URLs to the handler");
  }
  if (!content.includes("NoDisplay=true")) {
    throw new Error("URL handler desktop entry should be hidden from launchers");
  }
  if (!content.includes("MimeType=x-scheme-handler/codex-app-port;")) {
    throw new Error("URL handler desktop entry does not register the local scheme");
  }
  for (const forbidden of [
    "x-scheme-handler/codex;",
    "x-scheme-handler/codex://",
    `--no-${"sandbox"}`,
  ]) {
    if (content.includes(forbidden)) {
      throw new Error(`URL handler desktop entry contains forbidden marker ${forbidden}`);
    }
  }
}

function assertSanitizedEventStream(body) {
  for (const expected of [
    "event: ready",
    "event: notification",
    "event: done",
    "item/agentMessage/delta",
    "Live answer",
    "\"filtered\":true",
    "\"targetThreadIdSuffix\":\"abcd1234\"",
  ]) {
    if (!body.includes(expected)) {
      throw new Error(`event stream body is missing ${expected}`);
    }
  }
  for (const marker of [
    "Sensitive",
    "verify-sensitive-agent",
    "codexHome",
    "userAgent",
    ROOT,
    "/tmp/verify-private-home",
    "secret.txt",
    "sk-proj-verifysecret",
    "Excluded live answer",
    "wxyz9876",
    "../secret",
  ]) {
    if (body.includes(marker)) {
      throw new Error(`event stream payload leaked ${marker}`);
    }
  }
}

async function gitIndexEntry(workspace, path) {
  const info = await stat(join(workspace, path));
  return {
    path,
    size: info.size,
    mtimeSeconds: Math.floor(info.mtimeMs / 1000),
  };
}

async function writeGitIndex(path, entries) {
  const header = Buffer.alloc(12);
  header.write("DIRC", 0, "ascii");
  header.writeUInt32BE(2, 4);
  header.writeUInt32BE(entries.length, 8);
  const chunks = [header];
  for (const entry of entries) {
    const pathBytes = Buffer.from(entry.path, "utf8");
    const record = Buffer.alloc(62);
    record.writeUInt32BE(entry.mtimeSeconds, 8);
    record.writeUInt32BE(0o100644, 24);
    record.writeUInt32BE(entry.size, 36);
    record.writeUInt16BE(pathBytes.length, 60);
    const raw = Buffer.concat([record, pathBytes, Buffer.from([0])]);
    chunks.push(raw, Buffer.alloc((8 - (raw.length % 8)) % 8));
  }
  await writeFile(path, Buffer.concat(chunks));
}

function assertSanitizedGitWorktree(payload, { workspace }) {
  if (!payload.ok) {
    throw new Error("git worktree payload is not ok");
  }
  const serialized = JSON.stringify(payload);
  for (const marker of [
    workspace,
    "git@example.test",
    "private/repo",
    "codexHome",
    "userAgent",
    "/tmp/",
  ]) {
    if (serialized.includes(marker)) {
      throw new Error(`git worktree payload leaked ${marker}`);
    }
  }
  if (payload.workspace && Object.hasOwn(payload.workspace, "cwd")) {
    throw new Error("git worktree payload leaked workspace cwd");
  }
  const git = payload.git;
  if (!git?.isRepository || git.gitMetadataType !== "directory") {
    throw new Error("git worktree payload did not detect the test repository");
  }
  if (git.headKind !== "branch" || git.branch !== "feature/verify") {
    throw new Error("git worktree payload did not preserve branch metadata");
  }
  if (git.remoteCount !== 1 || git.linkedWorktreeCount !== 1) {
    throw new Error("git worktree payload did not preserve safe counts");
  }
  if (
    git.statusAvailable !== true ||
    git.statusMode !== "index-mtime-size" ||
    git.trackedFileCount !== 3 ||
    git.checkedTrackedFileCount !== 2 ||
    git.modifiedTrackedCount !== 1 ||
    git.missingTrackedCount !== 1 ||
    git.untrackedTopLevelCount !== 1
  ) {
    throw new Error("git worktree payload did not preserve read-only status counts");
  }
  if (git.localBranchCount !== 2 || git.returnedBranchCount !== 2) {
    throw new Error("git worktree payload did not preserve local branch inventory");
  }
  const currentBranch = git.branches?.find((branch) => branch.name === "feature/verify");
  if (!currentBranch?.current || currentBranch.commitShort !== "dddddddddddd") {
    throw new Error("git worktree payload did not preserve current branch inventory");
  }
  if (
    git.returnedLinkedWorktreeCount !== 1 ||
    git.linkedWorktrees?.[0]?.branch !== "release/linked"
  ) {
    throw new Error("git worktree payload did not preserve linked worktree inventory");
  }
  if (
    git.branchSwitchAvailable !== false ||
    git.commitActionsAvailable !== false ||
    git.followsLinkedGitDir !== false
  ) {
    throw new Error("git worktree payload unexpectedly enabled unsafe Git behavior");
  }
  assertGitBranchSwitchSafety(git.branchSwitchSafety);
  for (const forbidden of ["cwd", "path", "remoteUrl", "gitDir"]) {
    if (Object.hasOwn(git, forbidden)) {
      throw new Error(`git worktree payload leaked ${forbidden}`);
    }
  }
}

