function assertSanitizedThreadTranscript(payload) {
  if (!payload.ok) {
    throw new Error("thread transcript payload is not ok");
  }
  const serialized = JSON.stringify(payload);
  for (const marker of [
    "verify-sensitive-agent",
    "codexHome",
    "userAgent",
    "/tmp/codex-app-port-verify",
    "/tmp/verify-private-home",
    "secret.txt",
    "Sensitive thread title",
    "Sensitive thread preview",
  ]) {
    if (serialized.includes(marker)) {
      throw new Error(`thread transcript payload leaked ${marker}`);
    }
  }
  if (!serialized.includes("Sensitive user prompt") || !serialized.includes("Sensitive assistant content")) {
    throw new Error("thread transcript payload did not preserve conversation text");
  }
  const transcript = payload.probes?.threadTranscript;
  if (!transcript) {
    throw new Error("thread transcript payload is missing transcript");
  }
  for (const forbidden of ["id", "name", "preview", "cwd", "content", "path"]) {
    if (Object.hasOwn(transcript, forbidden)) {
      throw new Error(`thread transcript payload leaked ${forbidden}`);
    }
  }
  const item = transcript.turns?.[0]?.items?.[0];
  if (!item || item.role !== "user" || !item.text.includes("[path]")) {
    throw new Error("thread transcript payload did not sanitize transcript item text");
  }
}

function assertSanitizedThreadChanges(payload) {
  if (!payload.ok) {
    throw new Error("thread changes payload is not ok");
  }
  const serialized = JSON.stringify(payload);
  for (const marker of [
    "Sensitive",
    "verify-sensitive-agent",
    "codexHome",
    "userAgent",
    "/tmp/codex-app-port-verify",
    "/tmp/verify-private-home",
    "secret.txt",
    "sk-proj-verifysecret",
    "rm -rf",
  ]) {
    if (serialized.includes(marker)) {
      throw new Error(`thread changes payload leaked ${marker}`);
    }
  }
  if (!serialized.includes("verify-change.txt")) {
    throw new Error("thread changes payload did not preserve safe file basename");
  }
  if (!serialized.includes("+const verified = true;")) {
    throw new Error("thread changes payload did not preserve sanitized diff preview");
  }
  const changes = payload.probes?.threadChanges;
  if (!changes) {
    throw new Error("thread changes payload is missing changes");
  }
  for (const forbidden of ["id", "name", "preview", "cwd", "content", "text", "path"]) {
    if (Object.hasOwn(changes, forbidden)) {
      throw new Error(`thread changes payload leaked ${forbidden}`);
    }
  }
  const item = changes.turns?.[0]?.items?.[0];
  const change = item?.changes?.[0];
  if (!change || change.fileBasename !== "verify-change.txt" || change.additions !== 2) {
    throw new Error("thread changes payload did not preserve safe change metadata");
  }
  if (!change.diffPreview?.text?.includes("+const verified = true;")) {
    throw new Error("thread changes payload is missing sanitized diff preview");
  }
  for (const target of [item, change]) {
    for (const forbidden of ["content", "text", "path", "diff", "command"]) {
      if (Object.hasOwn(target, forbidden)) {
        throw new Error(`thread changes item leaked ${forbidden}`);
      }
    }
  }
  if (item.unsafeFieldsOmitted !== true || change.unsafeFieldsOmitted !== true) {
    throw new Error("thread changes payload did not mark omitted raw fields");
  }
}

async function readUiSessionToken(baseUrl) {
  const response = await fetch(`${baseUrl}/`);
  if (!response.ok) {
    throw new Error(`dev server UI returned HTTP ${response.status}`);
  }
  const csp = response.headers.get("content-security-policy") ?? "";
  if (!csp.includes("frame-ancestors 'none'")) {
    throw new Error("dev server UI is missing a restrictive CSP");
  }
  const html = await response.text();
  if (html.includes("__CODEX_APP_PORT_SESSION_TOKEN__")) {
    throw new Error("dev server UI leaked the raw session token placeholder");
  }
  if (!html.includes("approval-accept-all-button")) {
    throw new Error("dev server UI is missing the visible approval accept control");
  }
  if (!html.includes("approval-refresh-button") || !html.includes("approval-refresh-state")) {
    throw new Error("dev server UI is missing the approval refresh control");
  }
  if (!html.includes("settings-refresh-button") || !html.includes("settings-refresh-state")) {
    throw new Error("dev server UI is missing the settings refresh control");
  }
  const appResponse = await fetch(`${baseUrl}/assets/app.js`);
  if (!appResponse.ok) {
    throw new Error(`dev server UI script returned HTTP ${appResponse.status}`);
  }
  const appScript = await appResponse.text();
  for (const marker of [
    "approval-row-actions",
    "approvalDecisionButton",
    "approvalExecutionReadinessText",
    "approvalDecisionContractText",
    "approvalWorkflowContractText",
    "approvalSafetyContractText",
    "approvalAuditContractText",
    "approvalAuthorityContractText",
    "approvalInteractionContractText",
    "liveSessionInteractionContractText",
    "manualRefreshApprovalDecisions",
    "setApprovalRefreshState",
    "manualRefreshSettingsIntegrations",
    "setSettingsRefreshState",
    "turnExecutionAuthorityText",
    "turnSessionReadinessText",
    "turnSessionRoutingContractText",
    "turnSessionWorkflowContractText",
    "turnSessionSafetyContractText",
    "turnSessionAuditContractText",
    "approvalDecisionActionReady",
    "liveSessionRoutingContractText",
    "liveSessionWorkflowContractText",
    "liveSessionSafetyContractText",
    "liveSessionAuditContractText",
    "integrationAuditContractText",
    "integrationProvenanceContractText",
    "integrationExternalCodeContractText",
    "dataset.approvalDecisionAction",
    "aria-busy",
    "approvalDecisionProgressText",
  ]) {
    if (!appScript.includes(marker)) {
      throw new Error(`dev server UI script is missing approval row action marker ${marker}`);
    }
  }
  if (!html.includes("approval-execution-readiness")) {
    throw new Error("dev server UI is missing the approval execution readiness control");
  }
  if (!html.includes("approval-decision-contract")) {
    throw new Error("dev server UI is missing the approval decision contract control");
  }
  if (!html.includes("approval-workflow-contract")) {
    throw new Error("dev server UI is missing the approval workflow contract control");
  }
  if (!html.includes("approval-safety-contract")) {
    throw new Error("dev server UI is missing the approval safety contract control");
  }
  if (!html.includes("approval-audit-contract")) {
    throw new Error("dev server UI is missing the approval audit contract control");
  }
  if (!html.includes("approval-authority-contract")) {
    throw new Error("dev server UI is missing the approval authority contract control");
  }
  if (!html.includes("approval-interaction-contract")) {
    throw new Error("dev server UI is missing the approval interaction contract control");
  }
  if (!html.includes("turn-session-readiness")) {
    throw new Error("dev server UI is missing the turn session readiness control");
  }
  if (!html.includes("turn-execution-authority")) {
    throw new Error("dev server UI is missing the turn execution authority control");
  }
  if (!html.includes("turn-session-routing")) {
    throw new Error("dev server UI is missing the turn session routing control");
  }
  if (!html.includes("turn-session-workflow")) {
    throw new Error("dev server UI is missing the turn session workflow control");
  }
  if (!html.includes("turn-session-safety")) {
    throw new Error("dev server UI is missing the turn session safety control");
  }
  if (!html.includes("turn-session-audit")) {
    throw new Error("dev server UI is missing the turn session audit control");
  }
  if (!html.includes("live-session-safety")) {
    throw new Error("dev server UI is missing the live session safety control");
  }
  if (!html.includes("live-session-audit")) {
    throw new Error("dev server UI is missing the live session audit control");
  }
  if (!html.includes("live-session-interaction")) {
    throw new Error("dev server UI is missing the live session interaction control");
  }
  if (
    !html.includes("account-read-button") ||
    !html.includes("account-read-status") ||
    !html.includes("account-read-state-text") ||
    !html.includes("account-read-type-text") ||
    !appScript.includes("runAccountRead") ||
    !appScript.includes("renderAccountRead") ||
    !html.includes("account-login-button") ||
    !html.includes("account-login-cancel-button") ||
    !html.includes("account-reset-credit-button") ||
    !html.includes("account-reset-credit-status") ||
    !html.includes("account-reset-credit-history-count") ||
    !html.includes("account-reset-credit-history-list") ||
    !appScript.includes("runAccountResetCreditPreflight") ||
    !appScript.includes("runAccountResetCredit") ||
    !appScript.includes("renderAccountResetCreditHistory") ||
    !html.includes("account-login-history-list")
  ) {
    throw new Error("dev server UI is missing the account login controls");
  }
  if (
    !html.includes("integration-execution-readiness") ||
    !html.includes("integration-safety-contract") ||
    !html.includes("integration-routing-contract") ||
    !html.includes("integration-workflow-contract") ||
    !html.includes("integration-audit-contract") ||
    !html.includes("integration-provenance-contract") ||
    !html.includes("integration-external-code-contract") ||
    !appScript.includes("integrationExecutionReadinessText") ||
    !appScript.includes("integrationSafetyContractText") ||
    !appScript.includes("integrationRoutingContractText") ||
    !appScript.includes("integrationWorkflowContractText") ||
    !appScript.includes("integrationAuditContractText") ||
    !appScript.includes("integrationProvenanceContractText") ||
    !appScript.includes("integrationExternalCodeContractText")
  ) {
    throw new Error("dev server UI is missing the integration readiness controls");
  }
  const match = html.match(/name="codex-app-port-token" content="([^"]+)"/);
  if (!match?.[1]) {
    throw new Error("dev server UI did not inject a session token");
  }
  return match[1];
}

async function waitForManagedApproval(sessionManager, { workspace }) {
  for (let index = 0; index < 20; index += 1) {
    const pending = sessionManager.listApprovalRequests({ workspace });
    if (pending.length > 0) {
      return pending;
    }
    await new Promise((resolve) => setTimeout(resolve, 10));
  }
  return [];
}

function apiHeaders(token) {
  return {
    Accept: "application/json",
    [API_TOKEN_HEADER]: token,
  };
}

function jsonHeaders(token) {
  return {
    ...apiHeaders(token),
    "Content-Type": "application/json",
  };
}

function assertSanitizedStatus(payload, options = {}) {
  if (!payload.ok) {
    throw new Error("status payload is not ok");
  }
  const { forbidCodexBin = false, forbiddenPaths = [] } = options;
  const serialized = JSON.stringify(payload);
  for (const marker of ["codexHome", "userAgent"]) {
    if (serialized.includes(marker)) {
      throw new Error(`status payload leaked ${marker}`);
    }
  }
  for (const forbiddenPath of forbiddenPaths.filter(Boolean)) {
    if (serialized.includes(forbiddenPath)) {
      throw new Error(`status payload leaked path ${forbiddenPath}`);
    }
  }
  if (forbidCodexBin && Object.hasOwn(payload, "codex")) {
    throw new Error("API status payload leaked codex binary metadata");
  }
  if (payload.workspace && Object.hasOwn(payload.workspace, "cwd")) {
    throw new Error("API status payload leaked workspace cwd");
  }
  const items = [
    ...(payload.probes?.threads?.items ?? []),
    ...(payload.probes?.archivedThreads?.items ?? []),
  ];
  for (const item of items) {
    for (const forbidden of ["id", "name", "preview", "cwd"]) {
      if (Object.hasOwn(item, forbidden)) {
        throw new Error(`thread status payload leaked ${forbidden}`);
      }
    }
  }
}

function assertSanitizedWorkspaces(payload, { forbiddenPaths = [] } = {}) {
  if (!payload.ok || !Array.isArray(payload.workspaces) || payload.workspaces.length === 0) {
    throw new Error("workspaces payload is not ok");
  }
  const serialized = JSON.stringify(payload);
  for (const forbiddenPath of forbiddenPaths.filter(Boolean)) {
    if (serialized.includes(forbiddenPath)) {
      throw new Error(`workspaces payload leaked path ${forbiddenPath}`);
    }
  }
  for (const workspace of payload.workspaces) {
    for (const forbidden of ["cwd", "path"]) {
      if (Object.hasOwn(workspace, forbidden)) {
        throw new Error(`workspaces payload leaked ${forbidden}`);
      }
    }
  }
}

async function runJsonCommand(command, args, label, options = {}) {
  const result = await runCommand(command, args, label, { quiet: true, ...options });
  return JSON.parse(result.stdout);
}

async function runCommand(command, args, label, options = {}) {
  const { expectFailure = false, env = process.env, quiet = false } = options;
  if (!quiet) {
    process.stdout.write(`> ${label}\n`);
  }

  const result = await new Promise((resolve, reject) => {
    const child = spawn(command, args, {
      cwd: ROOT,
      env,
      stdio: ["ignore", "pipe", "pipe"],
    });

    let stdout = "";
    let stderr = "";
    child.stdout.setEncoding("utf8");
    child.stderr.setEncoding("utf8");
    child.stdout.on("data", (chunk) => {
      stdout += chunk;
    });
    child.stderr.on("data", (chunk) => {
      stderr += chunk;
    });
    child.on("error", reject);
    child.on("exit", (code, signal) => {
      resolve({ code, signal, stdout, stderr });
    });
  });

  const failed = result.code !== 0;
  if (expectFailure) {
    if (!failed) {
      throw new Error(`${label} was expected to fail but exited 0`);
    }
  } else if (failed) {
    throw new Error(
      `${label} failed with code=${result.code} signal=${result.signal}\n${result.stdout}\n${result.stderr}`,
    );
  }

  return result;
}

async function projectTextFiles() {
  const files = [];
  for (const entry of [
    ".gitignore",
    "README.md",
    "package.json",
    "docs",
    "scripts",
    "src",
    "test",
    "ui",
    "packaging",
  ]) {
    files.push(...(await walk(join(ROOT, entry))));
  }
  return files.filter(isTextFile);
}

async function testFiles() {
  const files = await walk(join(ROOT, "test"));
  return files.filter((file) => file.endsWith(".test.mjs"));
}

async function walk(path) {
  const info = await stat(path);
  if (info.isFile()) {
    return [path];
  }

  const entries = await readdir(path);
  const files = [];
  for (const entry of entries) {
    files.push(...(await walk(join(path, entry))));
  }
  return files;
}

function isTextFile(path) {
  return /\.(?:css|html|js|json|md|mjs|txt)$/.test(path) || path.endsWith(".gitignore");
}

function withoutEnv(source, keys) {
  const env = { ...source };
  for (const key of keys) {
    delete env[key];
  }
  return env;
}

function closeServer(server) {
  return new Promise((resolve, reject) => {
    server.close((error) => {
      if (error) {
        reject(error);
      } else {
        resolve();
      }
    });
  });
}

function relative(path) {
  return path.startsWith(ROOT) ? path.slice(ROOT.length) : path;
}

function pass(message) {
  process.stdout.write(`ok - ${message}\n`);
}

main().catch((error) => {
  process.stderr.write(`verify failed: ${error.message}\n`);
  process.exitCode = 1;
});
